// Load Google Cloud and notification config from n8n environment variables.
// These must be set in the n8n instance (Settings → Environment Variables)
// or via the N8N_ENVIRONMENT_VARIABLES docker env.

const config = {
  projectId:        $env.GOOGLE_CLOUD_PROJECT_ID        || '',
  location:         $env.GOOGLE_CLOUD_LOCATION          || 'us-central1',
  runtimeTemplate:  $env.GOOGLE_CLOUD_NOTEBOOK_RUNTIME_TEMPLATE || '',
  notebookGcsUri:   $env.COLAB_NOTEBOOK_GCS_URI         || '',
  outputGcsPrefix:  $env.COLAB_OUTPUT_GCS_PREFIX         || '',
  dataTeamEmail:    $env.DATA_TEAM_EMAIL                 || 'data-team@novaseat.dev',
  alertFromEmail:   $env.ALERT_FROM_EMAIL                || 'noreply@novaseat.dev',
  scoringRunId:     $input.first().json.id,
  scoringRunStart:  $input.first().json.started_at,
};

if (!config.projectId || !config.notebookGcsUri) {
  throw new Error(
    'Missing required env vars: GOOGLE_CLOUD_PROJECT_ID and COLAB_NOTEBOOK_GCS_URI must be set in n8n environment variables.'
  );
}

return [{ json: config }];

// Extract the execution job name from the API response for polling.
const response = $input.first().json;
const config = $('Load Config').first().json;

return [{
  json: {
    ...config,
    executionJobName: response.name || '',
    executionJobState: response.state || 'STATE_UNSPECIFIED',
  }
}];

// Check if the notebook execution has completed, failed, or is still running.
const response = $input.first().json;
const config = $('Load Config').first().json;
const state = (response.state || 'UNKNOWN').toUpperCase();

const terminalStates = ['SUCCEEDED', 'FAILED', 'CANCELLED', 'EXPIRED', 'INITIALIZING'];
const isComplete = state === 'SUCCEEDED';
const isFailed = ['FAILED', 'CANCELLED', 'EXPIRED'].includes(state);
const isRunning = !terminalStates.includes(state) || state === 'INITIALIZING';

return [{
  json: {
    ...config,
    executionState: state,
    isComplete,
    isFailed,
    isRunning,
    error: response.error || null,
  }
}];
